const body = $input.first().json.body || $input.first().json;
const alerts = body.alerts || [];
const status = body.status || 'firing';

// Mapa tag → email dev
const DEV_MAP = {
  'dev-fer':    'fernando.salva@griftin.com.ar',
  'dev-fer-s':    'fernando.salva@griftin.com.ar',
};

// Gaston recibe SIEMPRE todo
const ADMIN_EMAIL = 'gaston.villagra@griftin.com.ar';

if (alerts.length === 0) {
  const html = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">'
    + '<div style="background:#d97706;color:white;padding:16px;border-radius:8px 8px 0 0">'
    + '<h2 style="margin:0">⚠️ ALERTA SIN DETALLE</h2>'
    + '</div>'
    + '<div style="background:#f9fafb;padding:20px;border:1px solid #e5e7eb">'
    + '<p style="color:#374151">Payload recibido sin estructura de alertas.</p>'
    + '<pre style="background:#f3f4f6;padding:12px;border-radius:6px;font-size:12px">' + JSON.stringify(body, null, 2) + '</pre>'
    + '<hr style="border:none;border-top:1px solid #e5e7eb">'
    + '<p style="color:#9ca3af;font-size:12px">Griftin Monitor · ' + new Date().toLocaleString('es-AR', {timeZone:'America/Argentina/Salta'}) + '</p>'
    + '</div></div>';
  return [{ json: {
    emailSubject: '[Griftin Monitor] ⚠️ Alerta recibida sin detalle',
    emailBody: html,
    toEmail: ADMIN_EMAIL,
    alertname: 'AlertaGenérica'
  }}];
}

const results = [];

for (const alert of alerts) {
  const labels = alert.labels || {};
  const annotations = alert.annotations || {};
  const isFiring = status === 'firing';

  const bgColor   = isFiring ? '#dc2626' : '#16a34a';
  const titulo    = isFiring ? '🔴 ALERTA ACTIVA' : '✅ ALERTA RESUELTA';
  const severidad = (labels.severity || '').toUpperCase();
  const resumen   = annotations.summary || labels.alertname || 'Sin título';
  const descripcion = (annotations.description || '').trim();
  const fecha     = new Date().toLocaleString('es-AR', {timeZone:'America/Argentina/Salta'});

  // Detectar qué dev tags tiene la alerta del workflow
  const wfTags = (labels.tags || '').split(',').map(t => t.trim()).filter(Boolean);
  const devTags = wfTags.filter(t => DEV_MAP[t]);

  // Determinamos los destinatarios finales para ESTA alerta específica
  let recipients = [];

  if (devTags.length > 0) {
    // Si hay devs responsables asignados en los tags, se genera un mail para cada uno de ellos
    recipients = devTags.map(t => DEV_MAP[t]);
  } else {
    // Si la alerta no tiene ningún tag que coincida con un dev, te llega solo a vos como Admin
    recipients = [ADMIN_EMAIL];
  }

  // Aseguramos que no haya duplicados de mails en la lista de envíos para esta alerta
  const uniqueRecipients = [...new Set(recipients)];

  // Creamos un objeto de salida individual en n8n por cada destinatario
  for (const emailDestino of uniqueRecipients) {

    // Info visual para el cuerpo del mail (si es para un dev, le avisa su tag asignado)
    const devInfo = devTags.length > 0
      ? '<p style="font-size:14px;background:#eff6ff;padding:8px 12px;border-radius:6px;border-left:3px solid #3b82f6">'
        + '<strong>👤 Responsable asignado:</strong> ' + devTags.join(', ') + '</p>'
      : '';

    const html = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">'
      + '<div style="background:' + bgColor + ';color:white;padding:16px;border-radius:8px 8px 0 0">'
      + '<h2 style="margin:0;font-size:20px">' + titulo + '</h2>'
      + (severidad ? '<p style="margin:6px 0 0;opacity:0.9;font-size:13px">' + severidad + '</p>' : '')
      + '</div>'
      + '<div style="background:#f9fafb;padding:20px;border:1px solid #e5e7eb;border-top:none">'
      + '<h3 style="color:#111827;margin-top:0;font-size:16px">' + resumen + '</h3>'
      + (descripcion ? '<p style="color:#374151;font-size:14px;line-height:1.5">' + descripcion + '</p>' : '')
      + (labels.workflow_name ? '<p style="font-size:14px"><strong>Workflow:</strong> ' + labels.workflow_name + ' (ID: ' + labels.workflow_id + ')</p>' : '')
      + devInfo
      + (labels.tags ? '<p style="font-size:14px;color:#6b7280"><strong>Tags de la alerta:</strong> ' + labels.tags + '</p>' : '')
      + '<hr style="border:none;border-top:1px solid #e5e7eb;margin:16px 0">'
      + '<p style="color:#9ca3af;font-size:12px;margin:0">Griftin Monitor · ' + fecha + '</p>'
      + '</div></div>';

    results.push({
      json: {
        status,
        isFiring,
        alertname:    labels.alertname || 'Sin nombre',
        severity:     labels.severity  || 'unknown',
        summary:      resumen,
        description:  descripcion,
        workflowName: labels.workflow_name || '',
        workflowId:   labels.workflow_id   || '',
        tags:         labels.tags          || '',
        toEmail:      emailDestino, // <--- Destinatario ÚNICO para esta iteración
        emailSubject: '[Griftin Monitor] ' + (isFiring ? '🔴' : '✅') + ' ' + resumen,
        emailBody:    html
      }
    });
  }
}

return results;

